    {"quote": "Life is ten percent what happens to you and ninety percent how you respond to it.", "author": "Charles R. Swindoll", "theme": "Resilience", "tags": ["response", "resilience", "attitude"]},
    {"quote": "The only way to do great work is to love what you do.", "author": "Steve Jobs", "theme": "Meaning", "tags": ["work", "love", "passion"]},
    {"quote": "Stay hungry, stay foolish.", "author": "Steve Jobs", "theme": "Growth", "tags": ["curiosity", "growth", "risk"]},
    {"quote": "Your time is limited, so don't waste it living someone else's life.", "author": "Steve Jobs", "theme": "Authenticity", "tags": ["authenticity", "time", "identity"]},
    {"quote": "Innovation distinguishes between a leader and a follower.", "author": "Steve Jobs", "theme": "Growth", "tags": ["innovation", "leadership", "growth"]},
    {"quote": "Have the courage to follow your heart and intuition. They somehow already know what you truly want to become.", "author": "Steve Jobs", "theme": "Authenticity", "tags": ["intuition", "heart", "authenticity"]},
    {"quote": "You can't connect the dots looking forward; you can only connect them looking backwards.", "author": "Steve Jobs", "theme": "Acceptance", "tags": ["faith", "perspective", "acceptance"]},
    {"quote": "I'm as proud of many of the things we haven't done as the things we have done.", "author": "Steve Jobs", "theme": "Self-Awareness", "tags": ["focus", "choice", "self-awareness"]},
    {"quote": "Quality is more important than quantity. One home run is much better than two doubles.", "author": "Steve Jobs", "theme": "Simplicity", "tags": ["quality", "focus", "simplicity"]},
    {"quote": "Design is not just what it looks like and feels like. Design is how it works.", "author": "Steve Jobs", "theme": "Meaning", "tags": ["design", "function", "meaning"]},
    {"quote": "Sometimes life hits you in the head with a brick. Don't lose faith.", "author": "Steve Jobs", "theme": "Resilience", "tags": ["resilience", "faith", "adversity"]},
    {"quote": "Remembering that you are going to die is the best way I know to avoid the trap of thinking you have something to lose.", "author": "Steve Jobs", "theme": "Stoicism", "tags": ["mortality", "perspective", "stoicism"]},
    {"quote": "If you want to live your life in a creative way, as an artist, you have to not look back too much.", "author": "Steve Jobs", "theme": "Mindfulness", "tags": ["creativity", "presence", "mindfulness"]},
    {"quote": "Being the richest man in the cemetery doesn't matter to me. Going to bed at night saying we've done something wonderful... that's what matters to me.", "author": "Steve Jobs", "theme": "Meaning", "tags": ["meaning", "legacy", "value"]},
    {"quote": "My favorite things in life don't cost any money. It's really clear that the most precious resource we all have is time.", "author": "Steve Jobs", "theme": "Simplicity", "tags": ["time", "value", "simplicity"]},
    {"quote": "The ones who are crazy enough to think they can change the world are the ones who do.", "author": "Steve Jobs", "theme": "Courage", "tags": ["change", "belief", "courage"]},
    {"quote": "I think the things you regret most in life are the things you didn't do.", "author": "Steve Jobs", "theme": "Authenticity", "tags": ["regret", "action", "authenticity"]},
    {"quote": "Simple can be harder than complex: You have to work hard to get your thinking clean to make it simple.", "author": "Steve Jobs", "theme": "Simplicity", "tags": ["simplicity", "thinking", "focus"]},
    {"quote": "Focus means saying no to the hundred other good ideas that there are.", "author": "Steve Jobs", "theme": "Self-Care", "tags": ["focus", "boundaries", "self-care"]},
    {"quote": "Creativity is just connecting things.", "author": "Steve Jobs", "theme": "Growth", "tags": ["creativity", "connection", "growth"]},
    {"quote": "I want to put a ding in the universe.", "author": "Steve Jobs", "theme": "Meaning", "tags": ["impact", "meaning", "ambition"]},
    {"quote": "We're here to put a dent in the universe. Otherwise why else even be here?", "author": "Steve Jobs", "theme": "Meaning", "tags": ["purpose", "impact", "meaning"]},
    {"quote": "Your work is going to fill a large part of your life, and the only way to be truly satisfied is to do what you believe is great work.", "author": "Steve Jobs", "theme": "Meaning", "tags": ["work", "satisfaction", "meaning"]},
    {"quote": "I'm a big believer in boredom. Boredom allows one to indulge in curiosity.", "author": "Steve Jobs", "theme": "Mindfulness", "tags": ["boredom", "curiosity", "mindfulness"]},
    {"quote": "You've got to find what you love.", "author": "Steve Jobs", "theme": "Authenticity", "tags": ["love", "passion", "authenticity"]},
    {"quote": "I'm convinced that about half of what separates successful entrepreneurs from the non-successful ones is pure perseverance.", "author": "Steve Jobs", "theme": "Persistence", "tags": ["perseverance", "success", "persistence"]},
    {"quote": "The people who are doing the work are the moving force of the Mac.", "author": "Steve Jobs", "theme": "Harmony", "tags": ["teamwork", "harmony", "action"]},
    {"quote": "I think money is a wonderful thing because it enables you to do things.", "author": "Steve Jobs", "theme": "Simplicity", "tags": ["money", "utility", "simplicity"]},
    {"quote": "Everything around you that you call life was made up by people that were no smarter than you.", "author": "Steve Jobs", "theme": "Identity", "tags": ["reality", "identity", "empowerment"]},
    {"quote": "You can build your own things that other people can use.", "author": "Steve Jobs", "theme": "Meaning", "tags": ["creation", "utility", "meaning"]},
    {"quote": "Life can be much broader once you discover one simple fact: Everything around you that you call life was made up by people that were no smarter than you. And you can change it, you can influence it.", "author": "Steve Jobs", "theme": "Growth", "tags": ["growth", "influence", "reality"]},
    {"quote": "I am an optimist in the sense that I believe humans are noble and honorable, and some of them are really smart.", "author": "Steve Jobs", "theme": "Hope", "tags": ["optimism", "humanity", "hope"]},
    {"quote": "Technology is nothing. What's important is that you have a faith in people, that they're basically good and smart, and if you give them tools, they'll do wonderful things with them.", "author": "Steve Jobs", "theme": "Harmony", "tags": ["faith", "humanity", "harmony"]},
    {"quote": "We don't get a chance to do that many things, and every one should be really excellent.", "author": "Steve Jobs", "theme": "Meaning", "tags": ["excellence", "time", "meaning"]},
    {"quote": "I think different religions are different doors to the same house. Sometimes I think the house exists, and sometimes I don't. It's a great mystery.", "author": "Steve Jobs", "theme": "Acceptance", "tags": ["mystery", "faith", "acceptance"]},
    {"quote": "The heaviest burden is to have potential.", "author": "Charles Schulz", "theme": "Growth", "tags": ["potential", "burden", "growth"]},
    {"quote": "In the book of life, the answers aren't in the back.", "author": "Charles Schulz", "theme": "Self-Awareness", "tags": ["life", "answers", "self-awareness"]},
    {"quote": "I've developed a new philosophy. I only dread one day at a time.", "author": "Charles Schulz", "theme": "Mindfulness", "tags": ["mindfulness", "humor", "anxiety"]},
    {"quote": "Worrying doesn't help tomorrow's troubles, it only takes away today's peace.", "author": "Unknown", "theme": "Mindfulness", "tags": ["worry", "peace", "today"]},
    {"quote": "Yesterday is gone. Tomorrow has not yet come. We have only today. Let us begin.", "author": "Mother Teresa", "theme": "Mindfulness", "tags": ["today", "beginning", "mindfulness"]},
    {"quote": "The best preparation for tomorrow is doing your best today.", "author": "H. Jackson Brown Jr.", "theme": "Persistence", "tags": ["preparation", "today", "persistence"]},
    {"quote": "Start where you are. Use what you have. Do what you can.", "author": "Arthur Ashe", "theme": "Acceptance", "tags": ["action", "acceptance", "beginning"]},
    {"quote": "Change your thoughts and you change your world.", "author": "Norman Vincent Peale", "theme": "Growth", "tags": ["thoughts", "change", "growth"]},
    {"quote": "Believe in yourself! Have faith in your abilities!", "author": "Norman Vincent Peale", "theme": "Hope", "tags": ["belief", "faith", "hope"]},
    {"quote": "Empty pockets never held anyone back. Only empty heads and empty hearts can do that.", "author": "Norman Vincent Peale", "theme": "Persistence", "tags": ["persistence", "heart", "mind"]},
    {"quote": "Become a possibilitarian. No matter how dark things seem to be or actually are, raise your sights and see possibilities — always see them, for they're always there.", "author": "Norman Vincent Peale", "theme": "Hope", "tags": ["hope", "possibility", "optimism"]},
    {"quote": "Problems are not stop signs, they are guidelines.", "author": "Robert Schuller", "theme": "Resilience", "tags": ["problems", "guidelines", "resilience"]},
    {"quote": "If you can dream it, you can do it.", "author": "Walt Disney", "theme": "Hope", "tags": ["dreams", "achievement", "hope"]},
    {"quote": "The more you like yourself, the less you are like anyone else, which makes you unique.", "author": "Walt Disney", "theme": "Authenticity", "tags": ["uniqueness", "self-love", "authenticity"]},
    {"quote": "Laughter is timeless, imagination has no age, dreams are forever.", "author": "Walt Disney", "theme": "Meaning", "tags": ["laughter", "imagination", "dreams"]},
    {"quote": "When you believe in a thing, believe in it all the way, implicitly and unquestionable.", "author": "Walt Disney", "theme": "Courage", "tags": ["belief", "commitment", "courage"]},
    {"quote": "It's kind of fun to do the impossible.", "author": "Walt Disney", "theme": "Growth", "tags": ["impossible", "fun", "growth"]},
    {"quote": "We keep moving forward, opening new doors, and doing new things.", "author": "Walt Disney", "theme": "Growth", "tags": ["forward", "curiosity", "growth"]},
    {"quote": "The way to get started is to quit talking and begin doing.", "author": "Walt Disney", "theme": "Persistence", "tags": ["action", "beginning", "persistence"]},
    {"quote": "Disneyland will never be completed. It will continue to grow as long as there is imagination left in the world.", "author": "Walt Disney", "theme": "Growth", "tags": ["growth", "imagination", "process"]},
    {"quote": "A person should set his goals as early as he can and devote all his energy and talent to getting there.", "author": "Walt Disney", "theme": "Meaning", "tags": ["goals", "energy", "meaning"]},
    {"quote": "Get a good idea and stay with it. Dog it, and work at it until it's done right.", "author": "Walt Disney", "theme": "Persistence", "tags": ["persistence", "ideas", "completion"]},
    {"quote": "First, think. Second, believe. Third, dream. And finally, dare.", "author": "Walt Disney", "theme": "Courage", "tags": ["thought", "belief", "dare"]},
    {"quote": "You may not realize it when it happens, but a kick in the teeth may be the best thing in the world for you.", "author": "Walt Disney", "theme": "Resilience", "tags": ["adversity", "growth", "resilience"]},
    {"quote": "All our dreams can come true, if we have the courage to pursue them.", "author": "Walt Disney", "theme": "Hope", "tags": ["dreams", "courage", "hope"]},
    {"quote": "I am what I am.", "author": "Popeye", "theme": "Authenticity", "tags": ["authenticity", "identity", "simplicity"]},
    {"quote": "I can resist everything except temptation.", "author": "Oscar Wilde", "theme": "Acceptance", "tags": ["humor", "temptation", "acceptance"]},
    {"quote": "We are all in the gutter, but some of us are looking at the stars.", "author": "Oscar Wilde", "theme": "Hope", "tags": ["hope", "perspective", "stars"]},
    {"quote": "Be yourself; everyone else is already taken.", "author": "Oscar Wilde", "theme": "Authenticity", "tags": ["authenticity", "identity", "humor"]},
    {"quote": "Experience is simply the name we give our mistakes.", "author": "Oscar Wilde", "theme": "Acceptance", "tags": ["experience", "mistakes", "acceptance"]},
    {"quote": "Live! Live the wonderful life that is in you! Let nothing be lost upon you. Be always searching for new sensations. Be afraid of nothing.", "author": "Oscar Wilde", "theme": "Meaning", "tags": ["life", "sensation", "meaning"]},
    {"quote": "The only way to get rid of a temptation is to yield to it. Resist it, and your soul grows sick with longing for the things it has forbidden to itself.", "author": "Oscar Wilde", "theme": "Self-Awareness", "tags": ["temptation", "longing", "self-awareness"]},
    {"quote": "Selfishness is not living as one wishes to live, it is asking others to live as one wishes to live.", "author": "Oscar Wilde", "theme": "Authenticity", "tags": ["selfishness", "identity", "authenticity"]},
    {"quote": "A man who does not think for himself does not think at all.", "author": "Oscar Wilde", "theme": "Identity", "tags": ["thinking", "identity", "independence"]},
    {"quote": "The heart was made to be broken.", "author": "Oscar Wilde", "theme": "Acceptance", "tags": ["heart", "pain", "acceptance"]},
    {"quote": "Every saint has a past, and every sinner has a future.", "author": "Oscar Wilde", "theme": "Hope", "tags": ["hope", "future", "redemption"]},
    {"quote": "Wisdom is the reward you get for a lifetime of listening when you'd have preferred to talk.", "author": "Doug Larson", "theme": "Self-Awareness", "tags": ["wisdom", "listening", "self-awareness"]},
    {"quote": "The primary cause of unhappiness is never the situation but your thoughts about it.", "author": "Eckhart Tolle", "theme": "Mindfulness", "tags": ["thoughts", "unhappiness", "mindfulness"]},
    {"quote": "Acceptance looks like a passive state, but in reality it brings something entirely new into this world.", "author": "Eckhart Tolle", "theme": "Acceptance", "tags": ["acceptance", "peace", "power"]},
    {"quote": "Where there is anger, there is always pain underneath.", "author": "Eckhart Tolle", "theme": "Self-Awareness", "tags": ["anger", "pain", "self-awareness"]},
    {"quote": "Acknowledging the good that you already have in your life is the foundation for all abundance.", "author": "Eckhart Tolle", "theme": "Gratitude", "tags": ["gratitude", "abundance", "foundation"]},
    {"quote": "To offer no resistance to life is to be in a state of grace, ease, and lightness.", "author": "Eckhart Tolle", "theme": "Acceptance", "tags": ["resistance", "grace", "acceptance"]},
    {"quote": "Boredom is the same as the absence of a sense of purpose.", "author": "Eckhart Tolle", "theme": "Meaning", "tags": ["boredom", "purpose", "meaning"]},
    {"quote": "Life will give you whatever experience is most helpful for the evolution of your consciousness.", "author": "Eckhart Tolle", "theme": "Growth", "tags": ["evolution", "consciousness", "growth"]},
    {"quote": "Nothing ever happened in the past; it happened in the Now. Nothing will ever happen in the future; it will happen in the Now.", "author": "Eckhart Tolle", "theme": "Mindfulness", "tags": ["now", "time", "mindfulness"]},
    {"quote": "Awareness is the greatest agent for change.", "author": "Eckhart Tolle", "theme": "Self-Awareness", "tags": ["awareness", "change", "growth"]},
    {"quote": "The beginning of freedom is the realization that you are not 'the thinker.'", "author": "Eckhart Tolle", "theme": "Self-Awareness", "tags": ["freedom", "thinker", "self-awareness"]},
    {"quote": "You are not your mind.", "author": "Eckhart Tolle", "theme": "Identity", "tags": ["mind", "identity", "mindfulness"]},
    {"quote": "All problems are illusions of the mind.", "author": "Eckhart Tolle", "theme": "Mindfulness", "tags": ["problems", "illusions", "mindfulness"]},
    {"quote": "Power over others is weakness disguised as strength.", "author": "Eckhart Tolle", "theme": "Authenticity", "tags": ["power", "strength", "authenticity"]},
    {"quote": "Being at ease with not knowing is crucial for answers to come to you.", "author": "Eckhart Tolle", "theme": "Acceptance", "tags": ["knowing", "answers", "acceptance"]},
    {"quote": "The ego isn't wrong; it's just unconscious.", "author": "Eckhart Tolle", "theme": "Self-Awareness", "tags": ["ego", "unconscious", "self-awareness"]},
    {"quote": "The power of now is the power of your presence.", "author": "Eckhart Tolle", "theme": "Mindfulness", "tags": ["now", "presence", "mindfulness"]},
    {"quote": "Stay present, stay conscious.", "author": "Eckhart Tolle", "theme": "Mindfulness", "tags": ["presence", "consciousness", "mindfulness"]},
    {"quote": "Whatever you fight, you strengthen, and what you resist, persists.", "author": "Eckhart Tolle", "theme": "Acceptance", "tags": ["resistance", "persistence", "acceptance"]},
    {"quote": "Die to the past every moment.", "author": "Eckhart Tolle", "theme": "Mindfulness", "tags": ["past", "rebirth", "mindfulness"]},
    {"quote": "Life is the dancer and you are the dance.", "author": "Eckhart Tolle", "theme": "Meaning", "tags": ["life", "dance", "meaning"]},
    {"quote": "Presence is when you're no longer waiting for the next moment.", "author": "Eckhart Tolle", "theme": "Mindfulness", "tags": ["presence", "waiting", "mindfulness"]},
    {"quote": "The more you live in the now, the more you realize that there's nothing wrong.", "author": "Eckhart Tolle", "theme": "Acceptance", "tags": ["now", "perfection", "acceptance"]},
    {"quote": "Peace is the end of conflict with the present moment.", "author": "Eckhart Tolle", "theme": "Harmony", "tags": ["peace", "conflict", "harmony"]},
    {"quote": "Don't look for peace. Don't look for any other state than the one you are in now; otherwise, you will set up inner conflict and unconscious resistance.", "author": "Eckhart Tolle", "theme": "Acceptance", "tags": ["peace", "conflict", "acceptance"]},
    {"quote": "Forgive yourself for not being at peace.", "author": "Eckhart Tolle", "theme": "Compassion", "tags": ["forgiveness", "peace", "compassion"]},
    {"quote": "Thinking is only a small aspect of consciousness.", "author": "Eckhart Tolle", "theme": "Self-Awareness", "tags": ["thinking", "consciousness", "self-awareness"]},
    {"quote": "The brain does not create consciousness, but consciousness created the brain.", "author": "Eckhart Tolle", "theme": "Identity", "tags": ["brain", "consciousness", "identity"]},
    {"quote": "You are the universe expressing itself as a human for a little while.", "author": "Eckhart Tolle", "theme": "Identity", "tags": ["universe", "humanity", "identity"]},
    {"quote": "In stillness, you find yourself.", "author": "Eckhart Tolle", "theme": "Harmony", "tags": ["stillness", "self-discovery", "harmony"]},
    {"quote": "Nature will show you the way to stillness.", "author": "Eckhart Tolle", "theme": "Simplicity", "tags": ["nature", "stillness", "simplicity"]},
    {"quote": "The silence is a physical presence.", "author": "Eckhart Tolle", "theme": "Harmony", "tags": ["silence", "presence", "harmony"]},
    {"quote": "When you lose touch with inner stillness, you lose touch with yourself.", "author": "Eckhart Tolle", "theme": "Harmony", "tags": ["stillness", "identity", "harmony"]},
    {"quote": "Don't take your thoughts too seriously.", "author": "Eckhart Tolle", "theme": "Mindfulness", "tags": ["thoughts", "humor", "mindfulness"]},
    {"quote": "The light of consciousness is all that is necessary.", "author": "Eckhart Tolle", "theme": "Self-Awareness", "tags": ["light", "consciousness", "self-awareness"]},
    {"quote": "Love is a state of Being. Your love is not outside; it is deep within you.", "author": "Eckhart Tolle", "theme": "Identity", "tags": ["love", "being", "identity"]},
    {"quote": "The only source of happiness is within you.", "author": "Eckhart Tolle", "theme": "Harmony", "tags": ["happiness", "internal", "harmony"]},
    {"quote": "Death is the stripping away of all that is not you. The secret of life is to 'die before you die' — and find that there is no death.", "author": "Eckhart Tolle", "theme": "Meaning", "tags": ["death", "life", "meaning"]},
    {"quote": "Life is a mystery to be lived, not a problem to be solved.", "author": "Søren Kierkegaard", "theme": "Meaning", "tags": ["mystery", "life", "meaning"]},
    {"quote": "The most common form of despair is not being who you are.", "author": "Søren Kierkegaard", "theme": "Authenticity", "tags": ["despair", "identity", "authenticity"]},
    {"quote": "Prayer does not change God, but it changes him who prays.", "author": "Søren Kierkegaard", "theme": "Growth", "tags": ["prayer", "change", "growth"]},
    {"quote": "To dare is to lose one's footing momentarily. Not to dare is to lose oneself.", "author": "Søren Kierkegaard", "theme": "Courage", "tags": ["dare", "risk", "courage"]},
    {"quote": "If I were to wish for anything, I should not wish for wealth and power, but for the passionate sense of the potential.", "author": "Søren Kierkegaard", "theme": "Growth", "tags": ["potential", "passion", "growth"]},
    {"quote": "Anxiety is the dizziness of freedom.", "author": "Søren Kierkegaard", "theme": "Identity", "tags": ["anxiety", "freedom", "identity"]},
    {"quote": "Life can only be understood backwards; but it must be lived forwards.", "author": "Søren Kierkegaard", "theme": "Acceptance", "tags": ["understanding", "life", "acceptance"]},
    {"quote": "The function of prayer is not to influence God, but rather to change the nature of the one who prays.", "author": "Søren Kierkegaard", "theme": "Growth", "tags": ["prayer", "transformation", "growth"]},
    {"quote": "Deep within every man there lies a dread of having to live an ordinary life.", "author": "Søren Kierkegaard", "theme": "Meaning", "tags": ["dread", "ordinary", "meaning"]},
    {"quote": "People demand freedom of speech as a compensation for the freedom of thought which they seldom use.", "author": "Søren Kierkegaard", "theme": "Self-Awareness", "tags": ["freedom", "thought", "self-awareness"]},
    {"quote": "Patience is necessary, and one cannot reap immediately where one has sown.", "author": "Søren Kierkegaard", "theme": "Persistence", "tags": ["patience", "harvest", "persistence"]},
    {"quote": "The truth is a snare: you cannot have it, without being caught.", "author": "Søren Kierkegaard", "theme": "Authenticity", "tags": ["truth", "integrity", "authenticity"]},
    {"quote": "He who is always hoping for the best becomes old, and he who is always prepared for the worst becomes old early, but he who believes remains young.", "author": "Søren Kierkegaard", "theme": "Hope", "tags": ["hope", "belief", "youth"]},
    {"quote": "The more people who believe in something, the more likely it is to be false.", "author": "Søren Kierkegaard", "theme": "Identity", "tags": ["belief", "crowd", "identity"]},
    {"quote": "Trouble is the common denominator of living. It is the great equalizer.", "author": "Ann Landers", "theme": "Acceptance", "tags": ["trouble", "living", "acceptance"]},
    {"quote": "If you have no drive, you have no destination.", "author": "Ann Landers", "theme": "Meaning", "tags": ["drive", "destination", "meaning"]},
    {"quote": "Class is an aura of confidence that is being sure without being cocky. Class has nothing to do with money. Class never runs scared. It is self-discipline and self-knowledge.", "author": "Ann Landers", "theme": "Authenticity", "tags": ["class", "confidence", "authenticity"]},
    {"quote": "Expect problems and eat them for breakfast.", "author": "Alfred A. Montapert", "theme": "Resilience", "tags": ["problems", "breakfast", "resilience"]},
    {"quote": "The size of your success is measured by the strength of your desire; the size of your dream; and how you handle disappointment along the way.", "author": "Robert Kiyosaki", "theme": "Persistence", "tags": ["success", "dream", "disappointment"]},
    {"quote": "Don't let the fear of losing be greater than the excitement of winning.", "author": "Robert Kiyosaki", "theme": "Courage", "tags": ["fear", "excitement", "courage"]},
    {"quote": "Winners are not afraid of losing. But losers are. Failure is part of the process of success. People who avoid failure also avoid success.", "author": "Robert Kiyosaki", "theme": "Acceptance", "tags": ["failure", "success", "acceptance"]},
    {"quote": "In the real world, the smartest people are people who make mistakes and learn. In school, the smartest people don’t make mistakes.", "author": "Robert Kiyosaki", "theme": "Growth", "tags": ["mistakes", "learning", "growth"]},
    {"quote": "The only difference between a rich person and a poor person is how they use their time.", "author": "Robert Kiyosaki", "theme": "Meaning", "tags": ["time", "wealth", "meaning"]},
    {"quote": "F.E.A.R. has two meanings: 'Forget Everything And Run' or 'Face Everything And Rise.' The choice is yours.", "author": "Zig Ziglar", "theme": "Courage", "tags": ["fear", "choice", "courage"]},
    {"quote": "You don't have to be great to start, but you have to start to be great.", "author": "Zig Ziglar", "theme": "Growth", "tags": ["beginning", "greatness", "growth"]},
    {"quote": "Your attitude, not your aptitude, will determine your altitude.", "author": "Zig Ziglar", "theme": "Resilience", "tags": ["attitude", "altitude", "resilience"]},
    {"quote": "Positive thinking will let you do everything better than negative thinking will.", "author": "Zig Ziglar", "theme": "Mindfulness", "tags": ["positivity", "action", "mindfulness"]},
    {"quote": "Gratitude is the healthiest of all human emotions.", "author": "Zig Ziglar", "theme": "Gratitude", "tags": ["gratitude", "health", "emotions"]},
    {"quote": "If you can dream it, then you can achieve it.", "author": "Zig Ziglar", "theme": "Hope", "tags": ["dreams", "achievement", "hope"]},
    {"quote": "Success is the maximum utilization of the ability that you have.", "author": "Zig Ziglar", "theme": "Meaning", "tags": ["success", "ability", "meaning"]},
    {"quote": "A goal properly set is halfway reached.", "author": "Zig Ziglar", "theme": "Growth", "tags": ["goals", "growth", "planning"]},
    {"quote": "You were born to win, but to be a winner, you must plan to win, prepare to win, and expect to win.", "author": "Zig Ziglar", "theme": "Hope", "tags": ["winning", "planning", "hope"]},
    {"quote": "Character is the ability to carry out a good resolution long after the excitement of the moment has passed.", "author": "Cavett Robert", "theme": "Persistence", "tags": ["character", "resolution", "persistence"]},
    {"quote": "Discipline is doing what needs to be done, even if you don't want to do it.", "author": "Unknown", "theme": "Persistence", "tags": ["discipline", "willpower", "persistence"]},
    {"quote": "The best revenge is massive success.", "author": "Frank Sinatra", "theme": "Meaning", "tags": ["revenge", "success", "meaning"]},
    {"quote": "Success is getting what you want. Happiness is wanting what you get.", "author": "Dale Carnegie", "theme": "Gratitude", "tags": ["success", "happiness", "gratitude"]},
    {"quote": "Most of the important things in the world have been accomplished by people who have kept on trying when there seemed to be no hope at all.", "author": "Dale Carnegie", "theme": "Persistence", "tags": ["hope", "persistence", "achievement"]},
    {"quote": "Don't be afraid to give your best to what seemingly are small jobs. Every time you conquer one it makes you that much stronger.", "author": "Dale Carnegie", "theme": "Growth", "tags": ["growth", "strength", "effort"]},
    {"quote": "Inaction breeds doubt and fear. Action breeds confidence and courage.", "author": "Dale Carnegie", "theme": "Courage", "tags": ["action", "confidence", "courage"]},
    {"quote": "If you want to conquer fear, don't sit home and think about it. Go out and get busy.", "author": "Dale Carnegie", "theme": "Courage", "tags": ["fear", "action", "courage"]},
    {"quote": "One of the most tragic things I know about human nature is that all of us tend to put off living. We are all dreaming of some magical rose garden over the horizon instead of enjoying the roses that are blooming outside our windows today.", "author": "Dale Carnegie", "theme": "Mindfulness", "tags": ["living", "presence", "mindfulness"]},
    {"quote": "Are you bored with life? Then throw yourself into some work you believe in with all your heart, live for it, die for it, and you will find happiness that you had never dreamed could be yours.", "author": "Dale Carnegie", "theme": "Meaning", "tags": ["boredom", "work", "meaning"]},
    {"quote": "Our fatigue is often caused not by work, but by worry, frustration and resentment.", "author": "Dale Carnegie", "theme": "Self-Awareness", "tags": ["fatigue", "worry", "self-awareness"]},
    {"quote": "Flaming enthusiasm, backed up by horse sense and persistence, is the quality that most frequently makes for success.", "author": "Dale Carnegie", "theme": "Persistence", "tags": ["enthusiasm", "persistence", "success"]},
    {"quote": "First ask yourself: What is the worst that can happen? Then prepare to accept it. Then proceed to improve on the worst.", "author": "Dale Carnegie", "theme": "Stoicism", "tags": ["worst-case", "acceptance", "improvement"]},
    {"quote": "Happiness doesn't depend on any external conditions, it is governed by our mental attitude.", "author": "Dale Carnegie", "theme": "Harmony", "tags": ["happiness", "attitude", "harmony"]},
    {"quote": "The only way to get the best of an argument is to avoid it.", "author": "Dale Carnegie", "theme": "Harmony", "tags": ["argument", "peace", "harmony"]},
    {"quote": "You can make more friends in two months by becoming interested in other people than you can in two years by trying to get other people interested in you.", "author": "Dale Carnegie", "theme": "Compassion", "tags": ["friendship", "interest", "compassion"]},
    {"quote": "Talk to someone about themselves and they'll listen for hours.", "author": "Dale Carnegie", "theme": "Compassion", "tags": ["conversation", "ego", "compassion"]},
    {"quote": "If you want to keep a friend, never lend him money and never give him advice.", "author": "Dale Carnegie", "theme": "Harmony", "tags": ["friendship", "money", "harmony"]},
    {"quote": "Winning friends and influencing people is about genuine interest and empathy.", "author": "Dale Carnegie", "theme": "Compassion", "tags": ["influence", "empathy", "compassion"]},
    {"quote": "Criticism is dangerous, because it wounds a person's precious pride, hurts his sense of importance, and arouses resentment.", "author": "Dale Carnegie", "theme": "Compassion", "tags": ["criticism", "pride", "compassion"]},
    {"quote": "A man's name is to him the sweetest and most important sound in any language.", "author": "Dale Carnegie", "theme": "Identity", "tags": ["name", "identity", "language"]},
    {"quote": "The only way I can get you to do anything is by giving you what you want.", "author": "Dale Carnegie", "theme": "Meaning", "tags": ["desire", "motivation", "meaning"]},
    {"quote": "Act as if you were already happy and that will tend to make you happy.", "author": "Dale Carnegie", "theme": "Harmony", "tags": ["action", "happiness", "harmony"]},
    {"quote": "When dealing with people, let us remember we are not dealing with creatures of logic. We are dealing with creatures of emotion.", "author": "Dale Carnegie", "theme": "Compassion", "tags": ["emotion", "humanity", "compassion"]},
    {"quote": "Any fool can criticize, complain, and condemn—and most fools do. But it takes character and self-control to be understanding and forgiving.", "author": "Dale Carnegie", "theme": "Compassion", "tags": ["character", "understanding", "compassion"]},
    {"quote": "Flattery is from the teeth out. Sincere appreciation is from the heart out.", "author": "Dale Carnegie", "theme": "Authenticity", "tags": ["appreciation", "sincerity", "authenticity"]},
    {"quote": "The rare individual who unselfishly tries to serve others has an enormous advantage.", "author": "Dale Carnegie", "theme": "Meaning", "tags": ["service", "advantage", "meaning"]},
    {"quote": "A smile costs nothing but creates much. It enriches those who receive, without impoverishing those who give.", "author": "Dale Carnegie", "theme": "Gratitude", "tags": ["smile", "enrichment", "gratitude"]},
    {"quote": "The successful man will profit from his mistakes and try again in a different way.", "author": "Dale Carnegie", "theme": "Growth", "tags": ["mistakes", "profit", "growth"]},
    {"quote": "One reason why birds and horses are not unhappy is because they are not trying to impress other birds and horses.", "author": "Dale Carnegie", "theme": "Authenticity", "tags": ["comparison", "unhappiness", "authenticity"]},
    {"quote": "Do the thing you fear and the death of fear is certain.", "author": "Ralph Waldo Emerson", "theme": "Courage", "tags": ["fear", "action", "courage"]},
    {"quote": "The world makes way for the man who knows where he is going.", "author": "Ralph Waldo Emerson", "theme": "Meaning", "tags": ["direction", "world", "meaning"]},
    {"quote": "Great men are they who see that spiritual is stronger than any material force; that thoughts rule the world.", "author": "Ralph Waldo Emerson", "theme": "Mindfulness", "tags": ["thoughts", "spirit", "mindfulness"]},
    {"quote": "Shallow men believe in luck. Strong men believe in cause and effect.", "author": "Ralph Waldo Emerson", "theme": "Resilience", "tags": ["luck", "cause-effect", "resilience"]},
    {"quote": "Adopt the pace of nature: her secret is patience.", "author": "Ralph Waldo Emerson", "theme": "Simplicity", "tags": ["patience", "nature", "simplicity"]},
